class LmdbIndexAwareJoinOrderPlanningTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI RDF_TYPE = VF.createIRI("http://www.w3.org/1999/02/22-rdf-syntax-ns#type");
	private static final IRI GRID_SUBSTATION = VF.createIRI("http://example.com/theme/grid/Substation");
	private static final IRI GRID_GENERATOR = VF.createIRI("http://example.com/theme/grid/Generator");
	private static final IRI GRID_FEEDS = VF.createIRI("http://example.com/theme/grid/feeds");
	private static final IRI GRID_NAME = VF.createIRI("http://example.com/theme/grid/name");
	private static final IRI GRID_ALIAS = VF.createIRI("http://example.com/theme/grid/alias");
	private static final int SUBSTATION_COUNT = 300;
	private static final int GENERATOR_COUNT = 120;
	private static final int NOISE_COUNT = 600;

	@Test
	void plannerPrefersFeedsBeforeFilteredNameWithoutPosc(@TempDir File dataDir) throws Exception {
		PlannedBranch plannedBranch = planGeneratorBranch(dataDir, "spoc,ospc,psoc");
		Optional<JoinOrderPlanner.JoinOrderPlan> plan = plannedBranch.plan();

		assertTrue(plan.isPresent(), "Expected LMDB planner to produce a plan for the generator branch");
		List<TupleExpr> orderedArgs = plan.get().getOrderedArgs();
		assertEquals(4, orderedArgs.size(), "Expected four join factors in the generator branch");
		assertTrue(
				orderedArgs.indexOf(plannedBranch.feedsPattern()) < orderedArgs
						.indexOf(plannedBranch.filteredNamePattern()),
				"Without posc, LMDB planner should place grid:feeds before the filtered grid:name access");
	}

	@Test
	void plannerMayMoveFilteredNameEarlierWhenPoscExists(@TempDir File dataDir) throws Exception {
		PlannedBranch plannedBranch = planGeneratorBranch(dataDir, "spoc,ospc,psoc,posc");
		Optional<JoinOrderPlanner.JoinOrderPlan> plan = plannedBranch.plan();

		assertTrue(plan.isPresent(), "Expected LMDB planner to produce a plan for the generator branch");
		List<TupleExpr> orderedArgs = plan.get().getOrderedArgs();
		assertEquals(4, orderedArgs.size(), "Expected four join factors in the generator branch");
		assertTrue(
				orderedArgs.indexOf(plannedBranch.filteredNamePattern()) < orderedArgs
						.indexOf(plannedBranch.feedsPattern()),
				"With posc available, LMDB planner may use the grid:name filter before grid:feeds");
	}

	@Test
	void optimizedElectricalGridQueryKeepsFeedsBeforeNameInGeneratorBranch(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSyntheticGridData(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuildOnceSlow();

			try (SailRepositoryConnection connection = repository.getConnection()) {
				String explanationText = connection.prepareTupleQuery(electricalGridQuery())
						.explain(Explanation.Level.Optimized)
						.toString();
				int firstBindingIndex = explanationText.indexOf("BindingSetAssignment");
				int secondBindingIndex = explanationText.indexOf("BindingSetAssignment", firstBindingIndex + 1);
				int optionalBranchIndex = explanationText.indexOf("name=substation2", secondBindingIndex);

				assertTrue(firstBindingIndex >= 0, "Expected optimized explanation to include the first VALUES branch");
				assertTrue(secondBindingIndex >= 0,
						"Expected optimized explanation to include the generator VALUES branch");

				String generatorBranchText = optionalBranchIndex > secondBindingIndex
						? explanationText.substring(secondBindingIndex, optionalBranchIndex)
						: explanationText.substring(secondBindingIndex);
				int feedsIndex = generatorBranchText.indexOf("value=http://example.com/theme/grid/feeds");
				int nameIndex = generatorBranchText.indexOf("value=http://example.com/theme/grid/name");

				assertTrue(feedsIndex >= 0, "Expected generator branch explanation to contain grid:feeds");
				assertTrue(nameIndex >= 0, "Expected generator branch explanation to contain grid:name");
				assertTrue(feedsIndex < nameIndex,
						"Optimized electrical-grid explanation should keep grid:feeds before grid:name");
			}
		} finally {
			repository.shutDown();
		}
	}

	private static PlannedBranch planGeneratorBranch(File dataDir, String indexes) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig(indexes);
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSyntheticGridData(repository);
			SketchBasedJoinEstimator estimator = store.getBackingStore().getSketchBasedJoinEstimator();
			estimator.rebuildOnceSlow();

			StatementPattern typePattern = generatorTypePattern();
			StatementPattern feedsPattern = feedsPattern();
			Filter filteredNamePattern = filteredNamePattern();
			BindingSetAssignment targets = targetBindings();

			JoinOrderPlanner planner = (JoinOrderPlanner) store.getBackingStore().getEvaluationStatistics();
			return new PlannedBranch(
					planner.planJoinOrder(List.of(targets, typePattern, feedsPattern, filteredNamePattern),
							java.util.Set.of(),
							JoinOrderPlanner.Algorithm.DYNAMIC_PROGRAMMING),
					targets,
					typePattern,
					feedsPattern,
					filteredNamePattern);
		} finally {
			repository.shutDown();
		}
	}

	private static void loadSyntheticGridData(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int i = 0; i < SUBSTATION_COUNT; i++) {
				Resource substation = VF.createIRI("urn:test:substation:" + i);
				connection.add(substation, RDF_TYPE, GRID_SUBSTATION);
				connection.add(substation, GRID_NAME, VF.createLiteral("Substation " + i));
			}
			for (int i = 0; i < GENERATOR_COUNT; i++) {
				Resource generator = VF.createIRI("urn:test:generator:" + i);
				Resource substation = VF.createIRI("urn:test:substation:" + (i % 12));
				connection.add(generator, RDF_TYPE, GRID_GENERATOR);
				connection.add(generator, GRID_FEEDS, substation);
			}
			for (int i = 0; i < NOISE_COUNT; i++) {
				Resource aliasHolder = VF.createIRI("urn:test:alias-holder:" + i);
				connection.add(aliasHolder, GRID_ALIAS, VF.createLiteral("Substation " + (1 + (i % 3))));
			}
			connection.commit();
		}
	}

	private static StatementPattern generatorTypePattern() {
		return new StatementPattern(Var.of("entity"), Var.of("rdfType", RDF_TYPE),
				Var.of("generatorType", GRID_GENERATOR));
	}

	private static StatementPattern feedsPattern() {
		return new StatementPattern(Var.of("entity"), Var.of("feedsPredicate", GRID_FEEDS), Var.of("substation"));
	}

	private static Filter filteredNamePattern() {
		StatementPattern namePattern = new StatementPattern(Var.of("substation"), Var.of("namePredicate", GRID_NAME),
				Var.of("name"));
		return new Filter(namePattern,
				new Or(
						new Compare(Var.of("name"), Var.of("target"), Compare.CompareOp.EQ),
						new Compare(Var.of("name"), new ValueConstant(VF.createLiteral("Substation 3")),
								Compare.CompareOp.EQ)));
	}

	private static BindingSetAssignment targetBindings() {
		BindingSetAssignment bindingSetAssignment = new BindingSetAssignment();
		QueryBindingSet first = new QueryBindingSet();
		first.addBinding("target", VF.createLiteral("Substation 1"));
		QueryBindingSet second = new QueryBindingSet();
		second.addBinding("target", VF.createLiteral("Substation 2"));
		bindingSetAssignment.setBindingSets(List.<BindingSet>of(first, second));
		return bindingSetAssignment;
	}

	private static String electricalGridQuery() {
		return String.join("\n",
				"SELECT (COUNT(DISTINCT ?entity) AS ?count) WHERE {",
				"  {",
				"    VALUES ?target { \"Substation 1\" \"Substation 2\" }",
				"    ?entity a <http://example.com/theme/grid/Substation> .",
				"    ?entity <http://example.com/theme/grid/name> ?name .",
				"    FILTER ((?name = ?target) || (?name = \"Substation 3\"))",
				"  }",
				"  UNION",
				"  {",
				"    VALUES ?target { \"Substation 1\" \"Substation 2\" }",
				"    ?entity a <http://example.com/theme/grid/Generator> .",
				"    ?entity <http://example.com/theme/grid/feeds> ?substation .",
				"    ?substation <http://example.com/theme/grid/name> ?name .",
				"    FILTER ((?name = ?target) || (?name = \"Substation 3\"))",
				"  }",
				"  OPTIONAL {",
				"    ?entity <http://example.com/theme/grid/feeds> ?substation2 .",
				"  }",
				"}");
	}

	private record PlannedBranch(Optional<JoinOrderPlanner.JoinOrderPlan> plan, BindingSetAssignment targets,
			StatementPattern typePattern, StatementPattern feedsPattern, Filter filteredNamePattern) {
	}
}
